(window.webpackJsonp=window.webpackJsonp||[]).push([[58],{685:function(n,r){n.exports='\x3c!-- \r\ntitle: GithubAction\r\nsort: \r\n--\x3e \r\n\r\n```yml\r\non :\r\n  push:\r\n    branches:\r\n    # 指定分支\r\n    - master\r\n    # 指定路径\r\n    paths:\r\n    - *\r\njobs:\r\n  job1:\r\n    runs-on:ubuntu-latest\r\n  steps:\r\n  - uses:actions/checkout@v2\r\n  - uses:actions/setup-node@v1\r\n  with:\r\n  - node-version: ${{ env.NODE_VERSION }}\r\n  - run: |\r\n      npm install\r\n      npm run build--if-present\r\n      npm test\r\n```\r\n\r\n## Hexo\r\n\r\n```bash\r\n# 生成ssh密钥\r\nssh-keygen -f github-deploy-key\r\n# 将公私钥分别复制到静态界面仓库-配置仓库\r\nrepository->setting->secrets\r\nrepository->setting->\r\n\r\n# 创建Action配置文件\r\nblog (repository)\r\n└── .github\r\n    └── workflows\r\n        └── deploy.yml\r\n```\r\n\r\n> `deploy.yml`\r\n\r\n```yml\r\nname: HEXO_DEPLOY\r\n\r\non:\r\n  push:\r\n    branches:\r\n      - master\r\n\r\nenv:\r\n  GIT_USER: fzf404\r\n  GIT_EMAIL: nmdfzf404@163.com\r\n\r\njobs:\r\n  build:\r\n    runs-on: ubuntu-latest\r\n\r\n    steps:\r\n      - name: Checkout source\r\n        uses: actions/checkout@v2\r\n\r\n      - name: Use Node.js ${{ matrix.node_version }}\r\n        uses: actions/setup-node@v1\r\n        with:\r\n          version: ${{ matrix.node_version }}\r\n\r\n      - name: Setup hexo\r\n        env:\r\n          ACTION_DEPLOY_KEY: ${{ secrets.HEXO_DEPLOY_PRI }}\r\n\r\n        run: |\r\n          sudo timedatectl set-timezone "Asia/Shanghai"\r\n          mkdir -p ~/.ssh/\r\n          echo "$ACTION_DEPLOY_KEY" > ~/.ssh/id_rsa\r\n          chmod 600 ~/.ssh/id_rsa\r\n          ssh-keyscan github.com >> ~/.ssh/known_hosts\r\n          git config --global user.email $GIT_USER\r\n          git config --global user.name $GIT_EMAIL\r\n          npm install hexo-cli -g\r\n          npm install\r\n      - name: Hexo deploy\r\n        run: |\r\n          hexo clean\r\n          hexo d\r\n```\r\n\r\n> 拷贝hexo配置\r\n\r\n```\r\nthemes\r\n_config.yml\r\npackage.json\r\n```\r\n\r\n> 上传github\r\n\r\n```yml\r\ngit remote add origin git@github.com:xx/xx.git\r\ngit branch -M master\r\ngit push -u origin master\r\n```\r\n\r\n## 成功\r\n\r\n![image-20201204162421362](https://gitee.com/nmdfzf404/Image-hosting/raw/master/2020/20201204162428.png)\r\n\r\n'}}]);